import os
import re

BASE = r"C:\DAWID_PRACE\Anatomia\anatomy-3d\src\data"
ANATOMY_NOTES = r"C:\DAWID_PRACE\Anatomia\anatomy_notes_extracted.txt"

def read_file(path):
    with open(path, 'r', encoding='utf-8') as f:
        return f.read()

def write_file(path, content):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w', encoding='utf-8') as f:
        f.write(content)
    print(f"  Wrote: {path} ({len(content):,} chars, {content.count(chr(10))+1} lines)")

def load_anatomy_notes():
    """Load and parse the extracted anatomy notes."""
    if os.path.exists(ANATOMY_NOTES):
        with open(ANATOMY_NOTES, 'r', encoding='utf-8') as f:
            return f.read()
    return ""

